  <!-- ═══ 03 TYPOGRAPHY ═══ -->
  <section class="brand-section section-anchor" id="typography" >
    <div class="section-label">03 — Typography</div>
    <h2 class="section-title">Typography System</h2>
    <div class="section-divider"></div>
    <p class="section-intro">Three typefaces. Each with a distinct role. Together they form a typographic hierarchy that communicates editorial authority, professional readability, and technical precision — the voice of an enterprise brand that means business.</p>

    <!-- Bebas Neue Feature -->
    <div class="type-feature-block" style="margin-bottom:1.5rem;">
      <div class="type-eyebrow">Primary Display Typeface</div>
      <div class="type-sample-headline">Bebas Neue</div>
      <div style="display:flex; gap:3rem; align-items:flex-end; flex-wrap:wrap;">
        <div>
          <div style="font-family:'Bebas Neue',sans-serif; font-size:3.2rem; color:var(--cream); line-height:1; letter-spacing:1px; margin-bottom:0.3rem;">ABCDEFGHIJKLM</div>
          <div style="font-family:'Bebas Neue',sans-serif; font-size:3.2rem; color:rgba(238,240,236,0.38); line-height:1; letter-spacing:1px;">NOPQRSTUVWXYZ</div>
        </div>
        <div class="type-meta">Used for: Headlines · Hero Text · Section Titles<br><br>Weight: Regular (400)<br>Style: Display / All Caps<br>Tracking: 0–3px</div>
      </div>
    </div>

    <!-- Aptos + DM Mono -->
    <div style="display:grid;  gap:1.5rem; margin-bottom:2rem;">
      <div class="type-feature-block" style="background:var(--cream2);">
        <div class="type-eyebrow" style="color:var(--sage2);">Body Typeface</div>
        <div style="font-family:'Aptos',sans-serif; font-size:2.4rem; font-weight:700; color:var(--forest); line-height:1; margin-bottom:1rem;">Aptos</div>
        <div style="font-family:'Aptos',sans-serif; font-size:0.9rem; color:var(--sage2); line-height:1.75; margin-bottom:1rem;">The quick brown fox jumps over the lazy dog. Enterprise typography built for clarity and scale.</div>
        <div style="font-family:'DM Mono',monospace; font-size:0.63rem; color:var(--sage2); letter-spacing:2px; text-transform:uppercase;">Weight: 300 / 400 / 500 / 600 / 700<br>Use: Body · UI · Subheadings · Cards (Aptos)</div>
      </div>
    </div>

    <!-- Type Scale -->
    <div class="section-label" style="margin-bottom:0.5rem;">Type Scale</div>
    <div class="section-divider" style="margin-bottom:1.5rem;"></div>
    <div class="type-scale-grid">
