        </div>
        <div class="rule-meta">
          <div class="rule-title">Never distort or stretch the logo</div>
          <div class="rule-desc">Scale uniformly, preserving the original aspect ratio. Stretching or squashing destroys the geometric integrity of the mark.</div>
        </div>
      </div>
      <!-- DON'T 6 — stretched/distorted -->
      <div class="dont-card">
        <div class="rule-preview" style="background:var(--cream2);">
          <span class="rule-badge badge-dont">✗ Don't</span>
          <img
          src="data:image/svg+xml;base64,"
          alt="Mahathi logo"
          class="img-fluid"
          style="max-width:540px;width:100%;height:auto;"
