  <!-- ═══ 06 FAVICON & APP ICON ═══ -->
  <section class="brand-section section-anchor" id="visual-language" style="background-color: #e3e6e0;">
    <div class="section-label">06 — Digital Identity</div>
    <h2 class="section-title">Favicon &amp; App Icon</h2>
    <div class="section-divider"></div>
    <p class="section-intro">The Mahathi icon mark scales from 512px app icons down to 16px browser favicons. At small sizes the full wordmark drops away, leaving the petal spiral — an immediately recognisable identifier across all digital surfaces.</p>

    <!-- Icon mark SVG paths reused via a hidden def -->
